using System.Text; public static class ItemTextFormatter { public static string BuildFullInfo(ItemData item,int amount){ if(item==null)return "Нет данных."; StringBuilder b=new(); b.AppendLine($"Название: {item.DisplayName}"); b.AppendLine($"Количество: {amount}"); b.AppendLine($"Категория: {item.GetDisplayCategory()}"); b.AppendLine($"Вес: {item.Weight:0.##}"); b.AppendLine($"Стак: {item.MaxStackSize}"); if(item.CanUse())b.AppendLine($"Лечение: +{item.HealthRestore}"); if(item.CanEquip())b.AppendLine($"Экипировка: {item.EquipSlotId}, прочность {item.EquipmentMaxDurability}"); b.AppendLine(); b.AppendLine(string.IsNullOrWhiteSpace(item.Description)?"Без описания.":item.Description); return b.ToString().TrimEnd();} }